INSERT INTO places (name, slug, category, description, short_description, address, phone, website, price_range, rating, review_count, status, tags, images, latitude, longitude, is_verified, created_at) VALUES
('Cevahir Han', 'cevahir-han', 'restaurant', 'Şanlıurfa''nın en meşhur ciğer kebapçısı. Geleneksel yöntemlerle hazırlanan nefis ciğer kebabı ve özel acılı ezmesiyle ünlü.', 'Meşhur ciğer kebapçısı', 'Balıklıgöl Mevkii, Eski Şehir', '+90 414 215 00 00', 'https://cevahirhan.com', 2, 4.8, 1250, 'active', ARRAY['kebap', 'ciğer', 'geleneksel'], ARRAY['https://images.unsplash.com/photo-1603360946369-dc9bb6f54262?w=800', 'https://images.unsplash.com/photo-1544025162-d76978f8e4bb?w=800'], 37.1485, 38.7889, true, NOW()),
('Haşimiye Konağı', 'hasimiye-konagi', 'hotel', 'Balıklıgöl manzaralı, tarihi bir konağın restore edilmesiyle oluşturulmuş butik otel. Geleneksel mimari ile modern konfor bir arada.', 'Tarihi konağa otel', 'Haşimiye Mahallesi, No:15', '+90 414 316 16 16', 'https://hasimiyekonagi.com', 3, 4.6, 328, 'active', ARRAY['butik otel', 'tarihi', 'manzara'], ARRAY['https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800', 'https://images.unsplash.com/photo-1582719508461-905c673771fd?w=800'], 37.1489, 38.7892, true, NOW()),
('Balıklıgöl Café', 'balikligol-cafe', 'cafe', 'Balıklıgöl kenarında kahvenizi yudumlarken tarihi manzaranın tadını çıkarın. Gün batımında muhteşem fotoğraf noktası.', 'Göl manzaralı kafe', 'Balıklıgöl Yanı, Dergah', '+90 414 312 12 12', NULL, 1, 4.5, 892, 'active', ARRAY['kahve', 'manzara', 'gün batımı'], ARRAY['https://images.unsplash.com/photo-1554118811-1e0d58224f24?w=800', 'https://images.unsplash.com/photo-1445116572660-236099ec97a0?w=800'], 37.1482, 38.7885, false, NOW()),
('Şanlıurfa Arkeoloji Müzesi', 'arkeoloji-muzesi', 'museum', 'Göbeklitepe''den çıkarılan tarihi eserlerin sergilendiği modern müze. Neolitik döneme ait heykel ve taş oymaları görebilirsiniz.', 'Göbeklitepe eserleri', 'Harran Kapı Mahallesi', '+90 414 318 88 37', 'https://muze.gov.tr', 1, 4.7, 456, 'active', ARRAY['müze', 'tarih', 'göbeklitepe'], ARRAY['https://images.unsplash.com/photo-1566127444979-b3d2b654e3d7?w=800', 'https://images.unsplash.com/photo-1575223970966-76ae61ee7838?w=800'], 37.1534, 38.7923, true, NOW()),
('Fırfırlı Cami Çarşısı', 'firfirli-carsi', 'shopping', 'El işi ürünler, geleneksel Şanlıurfa halıları ve yöresel hediyelik eşyalar bulabileceğiniz tarihi çarşı.', 'Geleneksel el sanatları çarşısı', 'Fırfırlı Cami Yanı', NULL, NULL, 2, 4.3, 234, 'active', ARRAY['alışveriş', 'hediyelik', 'el işi'], ARRAY['https://images.unsplash.com/photo-1555529669-e69e7aa0ba9a?w=800'], 37.1478, 38.7881, false, NOW()),
('Gümrük Hanı', 'gumruk-hani', 'restaurant', 'Tarihi kervansarayın avlusunda, gölgesinde ağaçların altında otantik atmosferde yemek keyfi. Urfa kebabı ve borani denenmeli.', 'Tarihi kervansaray restoranı', 'Gümrük Hanı, Tarihi Çarşı', '+90 414 214 14 14', NULL, 2, 4.6, 678, 'active', ARRAY['restoran', 'tarihi', 'kebap'], ARRAY['https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=800'], 37.1467, 38.7876, true, NOW()),
('Karaköprü Parkı', 'karakopru-parki', 'park', 'Dicle Nehri kenarında yürüyüş yolları, piknik alanları ve çocuk oyun parklarıyla aileler için ideal mekan.', 'Dicle Nehri kenarı park', 'Karaköprü İlçesi', NULL, NULL, 0, 4.4, 312, 'active', ARRAY['park', 'doğa', 'aile'], ARRAY['https://images.unsplash.com/photo-1519331379826-fda8ebd5441d?w=800'], 37.1834, 38.7967, false, NOW()),
('Saray Kapı Eğlence Merkezi', 'saray-kapi-eglence', 'entertainment', ' bowling, bilardo, oyun makineleri ve sinema salonlarıyla gençlerin favori mekanı.', 'Eğlence ve oyun merkezi', 'Saray Kapı Mahallesi', '+90 414 345 45 45', NULL, 2, 4.2, 189, 'active', ARRAY['eglence', 'oyun', 'sinema'], ARRAY['https://images.unsplash.com/photo-1511512578047-dfb367046420?w=800'], 37.1591, 38.7969, false, NOW());
INSERT INTO historical_sites (name, slug, description, location, importance_level, visiting_hours, ticket_price, images, status, created_at) VALUES
('Göbeklitepe', 'gobeklitepe', 'Dünyanın bilinen en eski tapınak kompleksi. MÖ 9600-7300 yıllarına tarihlenen bu UNESCO Dünya Mirası alanı, insanlık tarihini yeniden yazdı.', 'Örencik Köyü, 18 km kuzeydoğu', 'critical', '08:00-18:00', 150, ARRAY['https://images.unsplash.com/photo-1599939571322-792a326991f2?w=800', 'https://images.unsplash.com/photo-1564507592333-c60657eea523?w=800'], 'active', NOW()),
('Balıklıgöl', 'balikligol', 'Hz. İbrahim''in ateşe atıldığında düştüğüne inanılan kutsal göl. Göldeki kutsal kızıl balıkların dokunulması yasaktır ve efsaneye göre yasaklara uymayanlar körlermiş.', 'Eski Şehir Merkezi', 'critical', '24 saat', 0, ARRAY['https://images.unsplash.com/photo-1545569341-9eb8b30979d9?w=800', 'https://images.unsplash.com/photo-1559563362-c667ba5f5480?w=800'], 'active', NOW()),
('Harran Örenyeri', 'harran-orenyeri', 'Dünyanın en eski üniversitesine ev sahipliği yapmış antik şehir. Kubbeli evleri ve antik kalıntılarıyla meşhur.', 'Harran İlçesi, 44 km güneydoğu', 'critical', '08:30-17:30', 50, ARRAY['https://images.unsplash.com/photo-1564507592333-c60657eea523?w=800'], 'active', NOW()),
('Urfa Kalesi', 'urfa-kalesi', 'Milattan önceki dönemlere dayanan tarihi kale. Şehrin en yüksek noktasında, tüm manzarayı görebileceğiniz mükemmel bir lokasyon.', 'Kale Mahallesi', 'high', '09:00-19:00', 0, ARRAY['https://images.unsplash.com/photo-1599939571322-792a326991f2?w=800'], 'active', NOW()),
('Rızvaniye Camii', 'rizvaniye-camii', 'Osmanlı dönemine ait, Balıklıgöl kenarındaki muhteşem cami. Gece aydınlatmasıyla birlikte muhteşem bir manzara sunar.', 'Balıklıgöl Yanı', 'medium', '24 saat', 0, ARRAY['https://images.unsplash.com/photo-1542273917363-3b1817f69a2d?w=800'], 'active', NOW());
INSERT INTO blog_posts (title, slug, excerpt, content, category, cover_image, is_published, is_featured, published_at, created_at) VALUES
('Göbeklitepe''ye Gidiş Rehberi: Tarihin Sıfır Noktası', 'gobeklitepe-rehberi', 'Dünyanın en eski tapınağına nasıl gidilir, ne zaman ziyaret edilir, püf noktalar nelerdir? Detaylı Göbeklitepe rehberi.', 'Göbeklitepe, Şanlıurfa''nın 18 km kuzeydoğusunda yer alıyor... [DETAYLI İÇERİK]', 'gezi-rehberi', 'https://images.unsplash.com/photo-1599939571322-792a326991f2?w=800', true, true, NOW(), NOW()),
('Urfa Kebabı vs Adana Kebabı: Farklar Nelerdir?', 'urfa-vs-adana-kebap', 'İki kebap arasındaki temel farkları, pişirme tekniklerini ve hangisini tercih etmeniz gerektiğini anlatıyoruz.', 'Urfa kebabı, Adana kebabından farklı olarak... [DETAYLI İÇERİK]', 'gastronomi', 'https://images.unsplash.com/photo-1603360946369-dc9bb6f54262?w=800', true, false, NOW(), NOW()),
('Harran''ın Sırları: Kubbeli Evler ve Antik Şehir', 'harran-sirlari', 'Peygamberler şehri Harran''ın bilinmeyenleri, kubbeli evlerin sırları ve gezilecek yerler.', 'Harran, tarih boyunca önemli bir kavşak noktası olarak... [DETAYLI İÇERİK]', 'tarih', 'https://images.unsplash.com/photo-1564507592333-c60657eea523?w=800', true, false, NOW(), NOW()),
('Şanlıurfa''da Çiğ Köfte Nerede Yenir? En İyi 10 Mekan', 'cig-kofte-en-iyi-mekanlar', 'Etsiz çiğ köftenin memleketinde en lezzetli çiğ köfteyi nerede bulursunuz? İşte yerel halkın favorileri.', 'Çiğ köfte, Urfa''nın vazgeçilmez lezzetlerinden... [DETAYLI İÇERİK]', 'gastronomi', 'https://images.unsplash.com/photo-1544025162-d76978f8e4bb?w=800', true, false, NOW(), NOW()),
('Balıklıgöl Efsanesi ve Kutsal Balıklar', 'balikligol-efsanesi', 'Hz. İbrahim ve Nemrud efsanesi, kutsal balıkların hikayesi ve Balıklıgöl''ün dini önemi.', 'Rivayete göre Nemrud, Hz. İbrahim''i ateşe atmak için... [DETAYLI İÇERİK]', 'kultur-sanat', 'https://images.unsplash.com/photo-1545569341-9eb8b30979d9?w=800', true, true, NOW(), NOW());
